import { readdir } from "node:fs/promises";
import { join, resolve } from "node:path";

import { pathExists, readTextFile } from "./fs-utils";
import type { CliError } from "./result-contracts";

export interface GateDiscoveryResult {
  status: "ready" | "needs-user-decision";
  verificationGates?: {
    storyGate: string;
    epicGate: string;
    storyGateSource: string;
    epicGateSource: string;
  };
  errors: CliError[];
  notes: string[];
}

interface GateSourceCandidates {
  story: string[];
  epic: string[];
  source: string;
}

function uniqueValues(values: string[]): string[] {
  return [...new Set(values.map((value) => value.trim()).filter(Boolean))];
}

function resolveGateValue(input: {
  explicitValue?: string;
  sourceCandidates: GateSourceCandidates[];
  gate: "story" | "epic";
}): {
  value?: string;
  source?: string;
  ambiguous: boolean;
} {
  if (input.explicitValue) {
    return {
      value: input.explicitValue,
      source: "explicit CLI flag",
      ambiguous: false,
    };
  }

  for (const candidateSet of input.sourceCandidates) {
    const values = uniqueValues(candidateSet[input.gate]);
    if (values.length > 1) {
      return {
        ambiguous: true,
      };
    }

    if (values.length === 1) {
      return {
        value: values[0],
        source: candidateSet.source,
        ambiguous: false,
      };
    }
  }

  return {
    ambiguous: false,
  };
}

async function packageScriptCandidates(
  specPackRoot: string
): Promise<GateSourceCandidates[]> {
  const packageJsonPath = join(specPackRoot, "package.json");
  if (!(await pathExists(packageJsonPath))) {
    return [];
  }

  const packageJson = JSON.parse(await readTextFile(packageJsonPath)) as {
    scripts?: Record<string, string>;
  };
  const scripts = packageJson.scripts ?? {};

  if (!scripts["green-verify"] && !scripts["verify-all"]) {
    return [];
  }

  return [
    {
      story: scripts["green-verify"] ? [scripts["green-verify"]] : [],
      epic: scripts["verify-all"] ? [scripts["verify-all"]] : [],
      source: "package.json scripts",
    },
  ];
}

async function docCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {
  const candidates: GateSourceCandidates = {
    story: [],
    epic: [],
    source: "project policy docs",
  };

  for (const fileName of ["AGENTS.md", "README.md"]) {
    const filePath = join(specPackRoot, fileName);
    if (!(await pathExists(filePath))) {
      continue;
    }

    const content = await readTextFile(filePath);
    for (const match of content.matchAll(/^Story Gate:\s*(.+)$/gim)) {
      candidates.story.push(match[1]);
    }
    for (const match of content.matchAll(/^Epic Gate:\s*(.+)$/gim)) {
      candidates.epic.push(match[1]);
    }
  }

  if (candidates.story.length === 0 && candidates.epic.length === 0) {
    return [];
  }

  return [candidates];
}

async function ciCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {
  const workflowsDir = join(specPackRoot, ".github", "workflows");
  if (!(await pathExists(workflowsDir))) {
    return [];
  }

  const entries = await readdir(workflowsDir, { withFileTypes: true });
  const candidates: GateSourceCandidates = {
    story: [],
    epic: [],
    source: "CI configuration",
  };

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.match(/\.ya?ml$/)) {
      continue;
    }

    const content = await readTextFile(join(workflowsDir, entry.name));
    for (const match of content.matchAll(/run:\s*(.+)$/gim)) {
      const command = match[1].trim();
      if (command.includes("green-verify")) {
        candidates.story.push(command);
      }
      if (command.includes("verify-all")) {
        candidates.epic.push(command);
      }
    }
  }

  if (candidates.story.length === 0 && candidates.epic.length === 0) {
    return [];
  }

  return [candidates];
}

export async function resolveVerificationGates(input: {
  specPackRoot: string;
  explicitStoryGate?: string;
  explicitEpicGate?: string;
}): Promise<GateDiscoveryResult> {
  const specPackRoot = resolve(input.specPackRoot);
  const sourceCandidates = [
    ...(await packageScriptCandidates(specPackRoot)),
    ...(await docCandidates(specPackRoot)),
    ...(await ciCandidates(specPackRoot)),
  ];
  const storyResolution = resolveGateValue({
    explicitValue: input.explicitStoryGate,
    sourceCandidates,
    gate: "story",
  });
  const epicResolution = resolveGateValue({
    explicitValue: input.explicitEpicGate,
    sourceCandidates,
    gate: "epic",
  });

  if (
    storyResolution.ambiguous ||
    epicResolution.ambiguous ||
    !storyResolution.value ||
    !epicResolution.value ||
    !storyResolution.source ||
    !epicResolution.source
  ) {
    return {
      status: "needs-user-decision",
      errors: [
        {
          code: "VERIFICATION_GATE_UNRESOLVED",
          message: "Verification gate policy is ambiguous",
          detail:
            "Provide --story-gate and --epic-gate explicitly or clarify the project policy.",
        },
      ],
      notes: [],
    };
  }

  return {
    status: "ready",
    verificationGates: {
      storyGate: storyResolution.value,
      epicGate: epicResolution.value,
      storyGateSource: storyResolution.source,
      epicGateSource: epicResolution.source,
    },
    errors: [],
    notes: [],
  };
}

import { execFile } from "node:child_process";
import { promisify } from "node:util";

import type { ImplRunConfig, SecondaryHarness } from "./config-schema";
import { resolveGitRepoRoot } from "./git-repo";
import type { HarnessAvailability, ProviderMatrix } from "./result-contracts";

const execFileAsync = promisify(execFile);
const DEFAULT_PROVIDER_CHECK_TIMEOUT_MS = 1_000;

function redactSensitiveText(text: string): string {
  return text
    .replace(/\bBearer\s+[A-Za-z0-9._-]+\b/gi, "Bearer [REDACTED]")
    .replace(/\b(token|auth|authorization|api[_-]?key)\s*[:=]\s*\S+/gi, "$1=[REDACTED]");
}

async function runCommand(params: {
  file: string;
  args: string[];
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}) {
  try {
    const result = await execFileAsync(params.file, params.args, {
      cwd: params.cwd,
      env: {
        ...process.env,
        ...params.env,
      },
      timeout: params.timeoutMs,
    });
    return {
      success: true as const,
      stdout: redactSensitiveText(result.stdout.trim()),
      stderr: redactSensitiveText(result.stderr.trim()),
    };
  } catch (error) {
    const failed = error as {
      stdout?: string;
      stderr?: string;
      code?: string | number;
      message?: string;
      killed?: boolean;
      signal?: string;
    };
    return {
      success: false as const,
      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
      stderr: redactSensitiveText(
        failed.stderr?.trim() ?? failed.message ?? String(error)
      ),
      code: failed.code,
      timedOut: failed.signal === "SIGTERM" || failed.killed === true,
    };
  }
}

function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
  switch (harness) {
    case "claude-code":
      return "claude";
    case "codex":
      return "codex";
    case "copilot":
      return "copilot";
    case "none":
      return null;
  }
}

function failureNotes(result: {
  stderr: string;
  timedOut?: boolean;
  code?: string | number;
}, executable: string, step: string): string[] {
  if (result.stderr) {
    return [result.stderr];
  }

  if (result.timedOut) {
    return [`${executable} ${step} timed out`];
  }

  return [`Unable to execute ${executable} ${step}`];
}

async function checkHarnessAvailability(input: {
  harness: "claude-code" | SecondaryHarness;
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}): Promise<HarnessAvailability> {
  const executable = executableForHarness(input.harness);
  if (!executable) {
    return {
      harness: "none",
      available: true,
      authStatus: "unknown",
      notes: [],
    };
  }

  const version = await runCommand({
    file: executable,
    args: ["--version"],
    cwd: input.cwd,
    env: input.env,
    timeoutMs: input.timeoutMs,
  });
  if (!version.success) {
    return {
      harness: input.harness,
      available: false,
      authStatus: version.code === "ENOENT" ? "missing" : "unknown",
      notes: failureNotes(version, executable, "--version"),
    };
  }

  const auth = await runCommand({
    file: executable,
    args: ["auth", "status"],
    cwd: input.cwd,
    env: input.env,
    timeoutMs: input.timeoutMs,
  });
  if (!auth.success) {
    const authStatus =
      auth.timedOut || auth.code === "ETIMEDOUT"
        ? "unknown"
        : auth.code === 1 || auth.stderr.toLowerCase().includes("missing")
          ? "missing"
          : "unknown";

    return {
      harness: input.harness,
      available: false,
      version: version.stdout,
      authStatus,
      notes: failureNotes(auth, executable, "auth status"),
    };
  }

  return {
    harness: input.harness,
    available: true,
    version: version.stdout,
    authStatus: "authenticated",
    notes: auth.stdout ? [auth.stdout] : [],
  };
}

function requestedSecondaryHarnesses(config: ImplRunConfig): SecondaryHarness[] {
  const harnesses = new Set<SecondaryHarness>();
  for (const assignment of [
    config.story_implementor,
    config.quick_fixer,
    config.story_verifier_1,
    config.story_verifier_2,
    ...config.epic_verifiers,
    config.epic_synthesizer,
  ]) {
    if (assignment.secondary_harness !== "none") {
      harnesses.add(assignment.secondary_harness);
    }
  }
  return [...harnesses];
}

export async function resolveProviderMatrix(input: {
  specPackRoot: string;
  config: ImplRunConfig;
  env?: Record<string, string | undefined>;
  timeoutMs?: number;
}): Promise<ProviderMatrix> {
  const cwd = (await resolveGitRepoRoot(input.specPackRoot)) ?? input.specPackRoot;
  const timeoutMs = input.timeoutMs ?? DEFAULT_PROVIDER_CHECK_TIMEOUT_MS;
  const primary = await checkHarnessAvailability({
    harness: "claude-code",
    cwd,
    env: input.env,
    timeoutMs,
  });
  const secondary: HarnessAvailability[] = [];

  for (const harness of requestedSecondaryHarnesses(input.config)) {
    secondary.push(
      await checkHarnessAvailability({
        harness,
        cwd,
        env: input.env,
        timeoutMs,
      })
    );
  }

  return {
    primary,
    secondary,
  };
}

