  const context = await prepareCleanupContext(input);
  if ("errors" in context) {
    return {
      outcome: "blocked",
      errors: context.errors,
      warnings: [],
    };
  }

  if (!hasApprovedCleanupItems(context.cleanupBatchContent)) {
    return {
      outcome: "cleaned",
      result: {
