    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.command).toBe("inspect");
  });

  test("persisted artifact json matches the stdout envelope", async () => {
    const specPackRoot = await createSpecPack("cli-io-artifact");
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);

    const envelope = parseJsonOutput<any>(run.stdout);
    const artifactPath = envelope.artifacts[0].path as string;
    const persisted = JSON.parse(await Bun.file(artifactPath).text());

    expect(persisted).toEqual(envelope);
  });
});

import { mkdir, readdir } from "node:fs/promises";
import { join, resolve } from "node:path";

import { writeTextFile } from "./fs-utils";

async function nextArtifactPathForGroup(
  specPackRoot: string,
  group: string,
  fileName: string
): Promise<string> {
  const artifactDir = join(resolve(specPackRoot), "artifacts", group);
  await mkdir(artifactDir, { recursive: true });

  const entries = await readdir(artifactDir, { withFileTypes: true });
  const existingCount = entries.filter(
    (entry) =>
      entry.isFile() && /^\d{3}-.+\.json$/.test(entry.name)
  ).length;
  const nextIndex = String(existingCount + 1).padStart(3, "0");

  return join(artifactDir, `${nextIndex}-${fileName}.json`);
}

export async function nextArtifactPath(
  specPackRoot: string,
  command: string
): Promise<string> {
  return nextArtifactPathForGroup(specPackRoot, command, command);
}

export async function nextGroupedArtifactPath(
  specPackRoot: string,
  group: string,
  fileName: string
): Promise<string> {
  return nextArtifactPathForGroup(specPackRoot, group, fileName);
}

export async function writeJsonArtifact(
  path: string,
  payload: unknown
): Promise<void> {
  await writeTextFile(path, `${JSON.stringify(payload)}\n`);
}

import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

export async function resolveGitRepoRoot(
  cwd: string
): Promise<string | null> {
  try {
    const { stdout } = await execFileAsync("git", ["rev-parse", "--show-toplevel"], {
      cwd,
    });
    const repoRoot = stdout.trim();
    return repoRoot.length > 0 ? repoRoot : null;
  } catch {
    return null;
  }
}

