      },
    ],
    selfReview: {
      findingsFixed: [],
      findingsSurfaced: [],
    },
    openQuestions: [],
    specDeviations: [],
    recommendedNextStep: "Run the fresh verifier batch for story-03.",
  };

  return {
    ...payload,
    ...overrides,
    selfReview: {
      ...payload.selfReview,
      ...overrides.selfReview,
