interface OutputEnvelope {
  command: string;
  version: 1;
  status: CliStatus;
  outcome: string;
  result?: unknown;
  errors: CliError[];
  warnings: string[];
  artifacts: CliArtifactRef[];
  startedAt: string;
  finishedAt: string;
}

function renderHumanSummary(envelope: OutputEnvelope) {
  if (
    typeof envelope.result !== "object" ||
    envelope.result === null ||
    !("providerMatrix" in envelope.result)
  ) {
    return `preflight: ${envelope.outcome}`;
  }

  const result = envelope.result as PreflightResult;
  const lines = [
    `preflight: ${envelope.outcome}`,
    `primary: ${result.providerMatrix.primary.available ? "ready" : "blocked"}`,
    `secondary: ${result.providerMatrix.secondary.length}`,
  ];

  if (result.verificationGates) {
    lines.push(`story gate: ${result.verificationGates.storyGate}`);
    lines.push(`epic gate: ${result.verificationGates.epicGate}`);
  }

  return lines.join("\n");
}

function emitOutput(params: {
  envelope: OutputEnvelope;
  json: boolean;
}) {
  if (params.json) {
    console.log(JSON.stringify(params.envelope));
    return;
  }

  console.log(renderHumanSummary(params.envelope));
}

function unavailableProviderErrors(
  providerMatrix: PreflightResult["providerMatrix"]
): CliError[] {
  const errors: CliError[] = [];

  if (!providerMatrix.primary.available) {
    errors.push({
      code: "PROVIDER_UNAVAILABLE",
      message: "Primary harness is unavailable",
      detail: providerMatrix.primary.notes.join("; "),
    });
  }

  for (const provider of providerMatrix.secondary) {
    if (!provider.available) {
      errors.push({
        code: "PROVIDER_UNAVAILABLE",
        message: `Requested secondary harness is unavailable: ${provider.harness}`,
        detail: provider.notes.join("; "),
      });
    }
  }

  return errors;
}

export default defineCommand({
  meta: {
    name: "preflight",
    description:
      "Validate run config, verification gates, and provider availability.",
  },
  args: {
    "spec-pack-root": {
      type: "string",
      description: "Absolute or relative path to the spec-pack root",
      required: true,
    },
    config: {
      type: "string",
      description: "Explicit run-config file relative to the spec-pack root",
    },
    "story-gate": {
      type: "string",
      description: "Explicit story verification gate command",
    },
    "epic-gate": {
      type: "string",
      description: "Explicit epic verification gate command",
    },
    json: {
    json: {
      type: "boolean",
      description: "Emit the structured JSON envelope on stdout",
    },
  },
  async run({ args }) {
    const startedAt = new Date().toISOString();

    try {
      const inspectResult = await inspectSpecPack(args["spec-pack-root"]);
      const artifactPath = await nextArtifactPath(
        inspectResult.specPackRoot,
        "preflight"
      );

      if (inspectResult.status !== "ready") {
        const envelope: OutputEnvelope = createResultEnvelope({
          command: "preflight",
          outcome: inspectResult.status,
          errors: [
            {
              code: "INVALID_SPEC_PACK",
              message:
                inspectResult.status === "blocked"
                  ? "Spec-pack inspection failed"
                  : "Spec-pack inspection requires a user decision",
              detail:
                inspectResult.blockers.join("; ") || inspectResult.notes.join("; "),
            },
          ],
          artifacts: [
            {
              kind: "result-envelope",
              path: artifactPath,
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        });

        await writeJsonArtifact(artifactPath, envelope);
        emitOutput({
          envelope,
          json: Boolean(args.json),
        });
        process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
        return;
      }

      const validatedConfig = await loadRunConfig({
        specPackRoot: inspectResult.specPackRoot,
        configPath: args.config,
      });
      const providerMatrix = await resolveProviderMatrix({
        specPackRoot: inspectResult.specPackRoot,
        config: validatedConfig,
        env: process.env,
      });
      const gateResolution = await resolveVerificationGates({
        specPackRoot: inspectResult.specPackRoot,
        explicitStoryGate: args["story-gate"],
        explicitEpicGate: args["epic-gate"],
      });
      const promptAssets = inspectPromptAssets();
      const notes = [...inspectResult.notes];

      if (
        [
          validatedConfig.story_implementor,
          validatedConfig.quick_fixer,
          validatedConfig.story_verifier_1,
          validatedConfig.story_verifier_2,
          ...validatedConfig.epic_verifiers,
          validatedConfig.epic_synthesizer,
        ].every((assignment) => assignment.secondary_harness === "none")
      ) {
        notes.push(
          "GPT-capable secondary harnesses are unavailable for this run; the orchestrator should record the Claude-only degraded mode."
        );
      }

      const providerErrors = unavailableProviderErrors(providerMatrix);
      const blockers: string[] = [];
      const errors: CliError[] = [];
      let outcome: "ready" | "needs-user-decision" | "blocked" = "ready";

      if (providerErrors.length > 0) {
        outcome = "blocked";
        errors.push(...providerErrors);
        blockers.push(...providerErrors.map((error) => error.message));
      } else if (!promptAssets.basePromptsReady || !promptAssets.snippetsReady) {
        outcome = "blocked";
        errors.push({
          code: "PROMPT_ASSET_MISSING",
          message: "Embedded prompt assets are incomplete",
          detail: promptAssets.notes.join("; "),
        });
        blockers.push("Embedded prompt assets are incomplete");
      } else if (gateResolution.status === "needs-user-decision") {
        outcome = "needs-user-decision";
        errors.push(...gateResolution.errors);
        notes.push(...gateResolution.notes);
      }

      const preflightResult: PreflightResult = {
        status: outcome,
        validatedConfig,
        providerMatrix,
        verificationGates: gateResolution.verificationGates,
        configValidationNotes: [],
        promptAssets,
        blockers,
        notes,
      };
      const envelope = cliResultEnvelopeSchema(preflightResultSchema).parse(
        createResultEnvelope({
          command: "preflight",
          outcome,
          result: preflightResult,
          errors,
          artifacts: [
            {
              kind: "result-envelope",
              path: artifactPath,
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        })
      );

      await writeJsonArtifact(artifactPath, envelope);
      emitOutput({
        envelope,
        json: Boolean(args.json),
      });
      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
    } catch (error) {
      if (
        error instanceof ZodError ||
        (error instanceof Error &&
          (error.message.includes("Cannot parse") ||
            error.message.includes("Required config") ||
            error.message.includes("JSON")))
      ) {
        const envelope: OutputEnvelope = createResultEnvelope({
          command: "preflight",
          outcome: "blocked",
          errors: [
            {
              code: "INVALID_RUN_CONFIG",
              message: "Run-config validation failed",
              detail: error instanceof Error ? error.message : String(error),
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        });

        emitOutput({
          envelope,

          envelope,
          json: Boolean(args.json),
        });
        process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
        return;
      }

      const envelope: OutputEnvelope = createResultEnvelope({
        command: "preflight",
        outcome: "error",
        errors: [
          {
            code: "UNEXPECTED_ERROR",
            message: error instanceof Error ? error.message : String(error),
          },
        ],
        startedAt,
        finishedAt: new Date().toISOString(),
      });

      emitOutput({
        envelope,
        json: Boolean(args.json),
      });
      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
    }
  },
});

import { execFile } from "node:child_process";
import { promisify } from "node:util";

import type { ImplRunConfig, SecondaryHarness } from "./config-schema";
import { resolveGitRepoRoot } from "./git-repo";
import type { HarnessAvailability, ProviderMatrix } from "./result-contracts";

const execFileAsync = promisify(execFile);
const DEFAULT_PROVIDER_CHECK_TIMEOUT_MS = 1_000;

function redactSensitiveText(text: string): string {
  return text
    .replace(/\bBearer\s+[A-Za-z0-9._-]+\b/gi, "Bearer [REDACTED]")
    .replace(/\b(token|auth|authorization|api[_-]?key)\s*[:=]\s*\S+/gi, "$1=[REDACTED]");
}

async function runCommand(params: {
  file: string;
  args: string[];
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}) {
  try {
    const result = await execFileAsync(params.file, params.args, {
      cwd: params.cwd,
      env: {
        ...process.env,
        ...params.env,
      },
      timeout: params.timeoutMs,
    });
    return {
      success: true as const,
      stdout: redactSensitiveText(result.stdout.trim()),
      stderr: redactSensitiveText(result.stderr.trim()),
    };
  } catch (error) {
    const failed = error as {
      stdout?: string;
      stderr?: string;
      code?: string | number;
      message?: string;
      killed?: boolean;
      signal?: string;
    };
    return {
      success: false as const,
      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
      stderr: redactSensitiveText(
        failed.stderr?.trim() ?? failed.message ?? String(error)
      ),
      code: failed.code,
      timedOut: failed.signal === "SIGTERM" || failed.killed === true,
    };
  }
}

function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
  switch (harness) {
    case "claude-code":
      return "claude";
    case "codex":
      return "codex";
    case "copilot":
      return "copilot";
    case "none":
      return null;
  }
}

function failureNotes(result: {
  stderr: string;
  timedOut?: boolean;
  code?: string | number;
}, executable: string, step: string): string[] {
  if (result.stderr) {
    return [result.stderr];
  }

  if (result.timedOut) {
    return [`${executable} ${step} timed out`];
  }

  return [`Unable to execute ${executable} ${step}`];
}

async function checkHarnessAvailability(input: {
  harness: "claude-code" | SecondaryHarness;
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}): Promise<HarnessAvailability> {
  const executable = executableForHarness(input.harness);
  if (!executable) {
    return {
      harness: "none",
      available: true,
      authStatus: "unknown",
      notes: [],
    };
  }

  const version = await runCommand({
    file: executable,
    args: ["--version"],
    cwd: input.cwd,
    env: input.env,
    timeoutMs: input.timeoutMs,
  });
  if (!version.success) {
    return {
      harness: input.harness,
      available: false,
      authStatus: version.code === "ENOENT" ? "missing" : "unknown",
      notes: failureNotes(version, executable, "--version"),
    };
  }

  const auth = await runCommand({
    file: executable,
    args: ["auth", "status"],
    cwd: input.cwd,
    env: input.env,
    timeoutMs: input.timeoutMs,
  });
  if (!auth.success) {
    const authStatus =
      auth.timedOut || auth.code === "ETIMEDOUT"
        ? "unknown"
        : auth.code === 1 || auth.stderr.toLowerCase().includes("missing")
          ? "missing"
          : "unknown";

    return {
      harness: input.harness,
      available: false,
      version: version.stdout,
      authStatus,
      notes: failureNotes(auth, executable, "auth status"),
    };
  }

  return {
    harness: input.harness,
    available: true,
    version: version.stdout,
    authStatus: "authenticated",
    notes: auth.stdout ? [auth.stdout] : [],
  };
}

function requestedSecondaryHarnesses(config: ImplRunConfig): SecondaryHarness[] {
  const harnesses = new Set<SecondaryHarness>();
  for (const assignment of [
    config.story_implementor,
    config.quick_fixer,
    config.story_verifier_1,
    config.story_verifier_2,
    ...config.epic_verifiers,
    config.epic_synthesizer,
  ]) {
    if (assignment.secondary_harness !== "none") {
      harnesses.add(assignment.secondary_harness);
    }
  }
  return [...harnesses];
}

export async function resolveProviderMatrix(input: {
  specPackRoot: string;
  config: ImplRunConfig;
  env?: Record<string, string | undefined>;
  timeoutMs?: number;
}): Promise<ProviderMatrix> {
  const cwd = (await resolveGitRepoRoot(input.specPackRoot)) ?? input.specPackRoot;
  const timeoutMs = input.timeoutMs ?? DEFAULT_PROVIDER_CHECK_TIMEOUT_MS;
  const primary = await checkHarnessAvailability({
    harness: "claude-code",
    cwd,
    env: input.env,
    timeoutMs,
  });
  const secondary: HarnessAvailability[] = [];

  for (const harness of requestedSecondaryHarnesses(input.config)) {
    secondary.push(
      await checkHarnessAvailability({
        harness,
        cwd,
        env: input.env,
        timeoutMs,
      })
    );
  }

  return {
    primary,
    secondary,
  };
}

